import { render, screen } from '@testing-library/react'
import { describe, expect, it } from 'vitest'
import App from './App'
import { links } from './data/links'

describe('App', () => {
  it('リンク数と同じ数のボタンを表示する', () => {
    render(<App />)

    const buttons = screen.getAllByRole('button')
    expect(buttons).toHaveLength(links.length)
  })

  it('各リンクに対応するアクセシブル名を持つ', () => {
    render(<App />)

    for (const link of links) {
      expect(screen.getByRole('button', { name: `Open ${link.name}` })).toBeInTheDocument()
    }
  })
})

import { LinkGrid } from './components/LinkGrid'
import { LinkCard } from './components/LinkCard'
import { links } from './data/links'

function App() {
    return (
        <main className="w-fit min-w-max p-3 min-h-0 m-0 flex flex-col items-center bg-[var(--bg-popup)] border border-[var(--border-subtle)] shadow-xl transition-colors duration-200">
            <LinkGrid>
                {links.map((link, index) => (
                    <LinkCard key={link.id} link={link} index={index} />
                ))}
            </LinkGrid>
        </main>
    )
}

export default App

import { links } from './data/links'

// コンテキストメニューの作成
chrome.runtime.onInstalled.addListener(() => {
    // 親メニューの作成
    chrome.contextMenus.create({
        id: 'ai-selector-parent',
        title: 'AI Selector で検索',
        contexts: ['selection']
    });

    // 検索URLが定義されているサービスのみサブメニューに追加
    links.forEach((link) => {
        if (link.searchUrl) {
            chrome.contextMenus.create({
                id: link.id,
                parentId: 'ai-selector-parent',
                title: link.name,
                contexts: ['selection']
            });
        }
    });
});

// メニュークリック時の処理
chrome.contextMenus.onClicked.addListener((info) => {
    const linkId = info.menuItemId as string;
    const selectionText = info.selectionText;

    if (!selectionText) return;

    const link = links.find(l => l.id === linkId);
    if (link && link.searchUrl) {
        const fullUrl = `${link.searchUrl}${encodeURIComponent(selectionText)}`;
        chrome.tabs.create({ url: fullUrl });
    }
});

import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { afterEach, describe, expect, it, vi } from 'vitest'
import { LinkCard } from './LinkCard'
import type { Link } from '../data/links'

const link: Link = {
  id: 'chatgpt',
  name: 'ChatGPT',
  description: 'Advanced conversational AI by OpenAI',
  url: 'https://chat.openai.com',
  category: 'LLM',
  icon: 'chatgpt.svg',
}

describe('LinkCard', () => {
  afterEach(() => {
    vi.restoreAllMocks()
    Reflect.deleteProperty(globalThis, 'chrome')
  })

  it('chrome.tabs.create が利用可能なら新規タブを開く', async () => {
    const createMock = vi.fn()
    const chromeMock = { tabs: { create: createMock } } as unknown as typeof chrome
    Object.defineProperty(globalThis, 'chrome', {
      value: chromeMock,
      configurable: true,
    })
    const openSpy = vi.spyOn(window, 'open')

    render(<LinkCard link={link} index={0} />)
    await userEvent.click(screen.getByRole('button', { name: 'Open ChatGPT' }))

    expect(createMock).toHaveBeenCalledWith({ url: link.url })
    expect(openSpy).not.toHaveBeenCalled()
  })

  it('chrome.tabs.create が使えない場合は window.open にフォールバックする', async () => {
    const openSpy = vi.spyOn(window, 'open').mockImplementation(() => null)

    render(<LinkCard link={link} index={0} />)
    await userEvent.click(screen.getByRole('button', { name: 'Open ChatGPT' }))

    expect(openSpy).toHaveBeenCalledWith(link.url, '_blank', 'noopener,noreferrer')
  })
})

import { useState } from 'react'
import type { Link } from '../data/links'
import { openInNewTab } from '../utils/browserUtils'
import { Tooltip } from './Tooltip'

interface LinkCardProps {
    link: Link
    index: number
}

export function LinkCard({ link, index }: LinkCardProps) {
    const [imgError, setImgError] = useState(false);
    const [isHovered, setIsHovered] = useState(false);

    // 14日以内なら NEW バッジを表示
    const isNew = (() => {
        if (!link.updatedAt) return false;
        const updatedDate = new Date(link.updatedAt);
        const now = new Date();
        const diffTime = Math.abs(now.getTime() - updatedDate.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return diffDays <= 14;
    })();

    return (
        <button
            onClick={() => openInNewTab(link.url)}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            onFocus={() => setIsHovered(true)}
            onBlur={() => setIsHovered(false)}
            className="relative flex items-center justify-center p-0 bg-transparent border-none shadow-none outline-none rounded-lg group w-[38px] h-[38px] cursor-pointer animate-pop-in opacity-0 fill-mode-forwards glow-hover hover:scale-110 hover:-translate-y-0.5"
            style={{
                animationDelay: `${index * 40}ms`,
                boxShadow: isHovered ? `0 0 12px 2px ${link.brandColor || '#4f46e5'}50` : 'none'
            }}
            aria-label={`Open ${link.name}`}
        >
            {isHovered && <Tooltip link={link} visible={isHovered} />}
            {isNew && (
                <div className="absolute top-[2px] right-[2px] w-1.5 h-1.5 bg-green-500 rounded-full new-badge z-10" aria-hidden="true" />
            )}
            <div className="w-full h-full flex items-center justify-center overflow-hidden rounded-lg">
                {!imgError ? (
                    <img
                        src={`/icons/${link.icon}`}
                        alt=""
                        loading="lazy"
                        decoding="async"
                        className="w-[24px] h-[24px] object-contain"
                        onError={() => setImgError(true)}
                    />
                ) : (
                    <span className="text-[10px] font-bold text-[var(--text-muted)]">
                        {link.name.substring(0, 2)}
                    </span>
                )}
            </div>
        </button>
    )
}

import type { ReactNode } from 'react'

interface LinkGridProps {
    children: ReactNode
}

export function LinkGrid({ children }: LinkGridProps) {
    return (
        // 要素を5列のグリッドで配置し、マウス移動距離を短縮するコンパクトなブロック状にする
        <div className="grid grid-cols-5 gap-1 justify-end place-items-center w-max p-0 m-0">
            {children}
        </div>
    )
}

import type { Link } from '../data/links'

interface TooltipProps {
    link: Link
    visible: boolean
}

export function Tooltip({ link, visible }: TooltipProps) {
    if (!visible) return null;

    const getCategoryStyles = (category: Link['category']) => {
        switch (category) {
            case 'LLM':
                return 'bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300';
            case 'Productivity':
                return 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300';
            case 'Dev':
                return 'bg-amber-100 text-amber-800 dark:bg-amber-900/40 dark:text-amber-300';
            default:
                return 'bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300';
        }
    }

    return (
        <div className="absolute z-50 bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 p-2 text-left bg-[var(--bg-popup)] border border-[var(--border-subtle)] shadow-xl rounded-lg pointer-events-none animate-tooltip-in">
            <div className="flex items-center justify-between mb-1">
                <span className="font-semibold text-xs text-[var(--text-primary)] leading-tight">{link.name}</span>
                <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-medium ${getCategoryStyles(link.category)}`}>
                    {link.category}
                </span>
            </div>
            <p className="text-[10px] text-[var(--text-muted)] leading-snug line-clamp-2 m-0">
                {link.description}
            </p>
        </div>
    )
}

import '@testing-library/jest-dom/vitest'
import { cleanup } from '@testing-library/react'
import { afterEach } from 'vitest'

afterEach(() => {
  cleanup()
})

/**
 * Opens a URL in a new tab, handling both extension and standard web environments.
 * @param url The URL to open
 */
export const openInNewTab = (url: string): void => {
    if (typeof chrome !== 'undefined' && chrome.tabs && chrome.tabs.create) {
        chrome.tabs.create({ url });
    } else {
        window.open(url, '_blank', 'noopener,noreferrer');
    }
};
